/**
 * A single point in a time series.
 */
export interface AnalyticsTimePoint {
  /** Bucket label (YYYY-MM-DD for daily, YYYY-MM for monthly). */
  period: string;
  value: number;
}

/**
 * Page-view totals and a daily time series.
 */
export interface AnalyticsViews {
  total: number;
  last7Days: number;
  last30Days: number;
  /** Views per day for the last 30 days (gap-filled). */
  daily: AnalyticsTimePoint[];
}

/**
 * View totals for a single post.
 */
export interface PostAnalytics {
  slug: string;
  /** All-time view count. */
  total: number;
  /** Views in the last 7 days. */
  last7Days: number;
  /** Views in the last 30 days. */
  last30Days: number;
}

/**
 * A leaderboard row ranked by page views.
 */
export interface AnalyticsLeader {
  slug: string;
  name: string;
  views: number;
}

/**
 * A referrer-host row ranked by page views.
 */
export interface AnalyticsReferrer {
  /** Coarse referrer host (e.g. "www.google.com"). Empty string means the view had no referrer (direct, same-origin or app traffic). */
  host: string;
  views: number;
}

/**
 * SEO completeness across published-eligible posts.
 */
export interface AnalyticsSeo {
  /** Mean SEO completeness score (0-100) across all posts. */
  averageScore: number;
  /** Posts scoring 80 or above. */
  fullyOptimized: number;
  /** Posts scoring below 50. */
  needsWork: number;
  total: number;
}

/**
 * Content-health counters.
 */
export interface AnalyticsHealth {
  brokenLinks: number;
  validationFailures: number;
  drafts: number;
  scheduled: number;
}

/**
 * Summary of the most recent automated storage-cleanup (page-views rollup) run, sourced from the null-actor `analytics.rollup.auto` audit log row. Lets operators confirm the scheduled job is firing without leaving the analytics screen.
 */
export interface AnalyticsMaintenance {
  /** When the most recent rollup run was recorded. */
  lastRunAt: string;
  /** Raw page_views rows folded into the rollup and deleted. */
  rolledRows: number;
  /** Distinct calendar days folded in that run. */
  days: number;
  /** Distinct (day, slug) daily buckets written/updated. */
  buckets: number;
  /** Distinct (day, referrer host) buckets written/updated. */
  referrerBuckets: number;
  /** Raw rows older than this timestamp were rolled up and removed. */
  cutoff: string;
}

export interface CmsAnalytics {
  generatedAt: string;
  views: AnalyticsViews;
  topPages: AnalyticsLeader[];
  topAuthors: AnalyticsLeader[];
  topCategories: AnalyticsLeader[];
  topTags: AnalyticsLeader[];
  /** Top referrer hosts driving views. */
  topReferrers: AnalyticsReferrer[];
  seo: AnalyticsSeo;
  /** Posts published per month for the last 12 months. */
  publishingVelocity: AnalyticsTimePoint[];
  /** Cumulative post count at each month end for the last 12 months. */
  contentGrowth: AnalyticsTimePoint[];
  health: AnalyticsHealth;
  /** Most recent automated storage-cleanup (page-views rollup) run, or null if the scheduled job has never recorded a run. */
  maintenance: AnalyticsMaintenance | null;
}

/**
 * Whether the target resolves on the blog or to an external origin.
 */
export type DeactivatedRedirectKind = typeof DeactivatedRedirectKind[keyof typeof DeactivatedRedirectKind];


export const DeactivatedRedirectKind = {
  'on-blog': 'on-blog',
  'off-blog': 'off-blog',
} as const;

/**
 * Why the auto-deactivator flipped isActive to false. Null while active.
 * @nullable
 */
export type DeactivatedRedirectDeactivatedReason = typeof DeactivatedRedirectDeactivatedReason[keyof typeof DeactivatedRedirectDeactivatedReason] | null;


export const DeactivatedRedirectDeactivatedReason = {
  'on-blog-target-missing': 'on-blog-target-missing',
  'off-blog-target-dead': 'off-blog-target-dead',
} as const;

export interface DeactivatedRedirect {
  id: string;
  fromPath: string;
  toPath: string;
  statusCode: number;
  isActive: boolean;
  /** Whether the target resolves on the blog or to an external origin. */
  kind: DeactivatedRedirectKind;
  /**
     * Why the auto-deactivator flipped isActive to false. Null while active.
     * @nullable
     */
  deactivatedReason: DeactivatedRedirectDeactivatedReason;
  /** @nullable */
  deactivatedAt: string | null;
  /**
     * Last observed final HTTP status for an off-blog target (null for on-blog).
     * @nullable
     */
  targetLastStatus: number | null;
  /** @nullable */
  targetCheckedAt: string | null;
  /** Consecutive confirmed-dead readings of the target. */
  targetCheckFailures: number;
}

export interface DeactivatedRedirectListResponse {
  /** Redirects auto-deactivated because their target is confirmed dead. */
  deactivated: DeactivatedRedirect[];
  /** Still-active off-blog redirects that failed at least once but haven't reached the deactivation threshold yet. */
  atRisk: DeactivatedRedirect[];
}

